import json
with open('baseline-packages.json') as f: baseline = json.load(f)
with open('after-cpm-packages.json') as f: after = json.load(f)

# Build lookup: {(project_basename, framework, package_id): version}
def build_map(data):
    m = {}
    for p in data['projects']:
        name = p['path'].split('/')[-1]
        for fw in p['frameworks']:
            for pkg in fw.get('topLevelPackages', []):
                m[(name, fw['framework'], pkg['id'])] = pkg['resolvedVersion']
    return m

bm = build_map(baseline)
am = build_map(after)

changes = []
unchanged = []
all_keys = sorted(set(list(bm.keys()) + list(am.keys())))
for k in all_keys:
    bv = bm.get(k)
    av = am.get(k)
    if bv != av:
        changes.append((k[0], k[1], k[2], bv or 'N/A', av or 'N/A'))
    else:
        unchanged.append((k[0], k[1], k[2], bv))

if changes:
    print('CHANGES:')
    print(f'{\"Project\":<15} {\"Framework\":<10} {\"Package\":<45} {\"Before\":<12} {\"After\":<12}')
    print('-' * 94)
    for c in changes:
        print(f'{c[0]:<15} {c[1]:<10} {c[2]:<45} {c[3]:<12} {c[4]:<12}')
else:
    print('No changes detected.')

print()
print(f'Unchanged packages: {len(unchanged)}')
"

